  { id: "custom", name: "Custom Background", colors: "bg-surface border-border border-dashed text-white" },
];

// LinkItem Interface
export interface LinkItem {
  id: string;
  slug: string;
  destination_url: string;
  clicks_count: number;
  active: boolean;
  created: string;
  title?: string;
  order?: number;
  show_on_profile?: boolean;
  mode?: string;
  icon_type?: "preset" | "emoji" | "custom" | "none";
  icon_value?: string;
  size?: "regular" | "large";
  bg_image?: string;
}

interface SocialLink {
  id: string;
  url: string;
  icon_type: "preset" | "emoji" | "custom" | "none";
  icon_value: string;
  label?: string;
}

export default function DashboardProfile() {
  const { user } = useAuth();

  const [profileLoading, setProfileLoading] = useState(false);
  const [name, setName] = useState("");
  const [username, setUsername] = useState("");
  const [bio, setBio] = useState("");
  const [theme, setTheme] = useState(user?.theme || "minimal-dark");
  const userPlan = (user as { plan?: string })?.plan || "creator";
  const canCustomize = checkPlan(userPlan, "profile_customization");
  const [avatarPreview, setAvatarPreview] = useState<string | null>(null);
  const [avatarFile, setAvatarFile] = useState<File | null>(null); // Actual file to upload
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Custom Theme Background State
  const [customBgPreview, setCustomBgPreview] = useState<string | null>(null);
  const [customBgFile, setCustomBgFile] = useState<File | null>(null);
  const customBgInputRef = useRef<HTMLInputElement>(null);

  // Avatar Cropper State
  const [imageToCrop, setImageToCrop] = useState<string | null>(null);
  const [crop, setCrop] = useState<Point>({ x: 0, y: 0 });
  const [zoom, setZoom] = useState(1);
  const [croppedAreaPixels, setCroppedAreaPixels] = useState<Area | null>(null);

  // Links State
  const [links, setLinks] = useState<LinkItem[]>([]);
  const [linksLoading, setLinksLoading] = useState(true);
  const [socialLinks, setSocialLinks] = useState<SocialLink[]>([]);

  // Inline Create State
  const [showCreate, setShowCreate] = useState(false);
  const [createTitle, setCreateTitle] = useState("");
  const [createUrl, setCreateUrl] = useState("");
  const [createLoading, setCreateLoading] = useState(false);
  const [createIconType, setCreateIconType] = useState<"preset" | "emoji" | "custom" | "none">("none");
  const [createIconValue, setCreateIconValue] = useState("");
  const [showIconPicker, setShowIconPicker] = useState(false);
  const [createSize, setCreateSize] = useState<"regular" | "large">("regular");
  const [refreshing, setRefreshing] = useState(false); // Added from user's snippet
  const [socialEditingId, setSocialEditingId] = useState<string | null>(null);

  // Pending bg_image uploads/removals for when handleSaveProfile runs
  const [pendingBgImages, setPendingBgImages] = useState<Record<string, { file: File | null; remove: boolean }>>({});


  useEffect(() => {
    if (user) {
      // Load user profile
      setName(user.name || "");
      setUsername(user.username || "");
      setBio(user.bio || "");
      // theme is initialized directly in useState to prevent flashing
      if (user.avatar && user.collectionId) {
        setAvatarPreview(pb.files.getUrl(user as unknown as Record<string, unknown>, user.avatar));
      }
      if (user.custom_theme_bg && user.collectionId) {
        setCustomBgPreview(pb.files.getUrl(user as unknown as Record<string, unknown>, user.custom_theme_bg));
      }
      if (user.social_links) {
        setSocialLinks(Array.isArray(user.social_links) ? (user.social_links as unknown as SocialLink[]) : []);
      }
      // Load links
      fetchLinks();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user]);

  // Auto-detect icon based on URL input
  useEffect(() => {
    if (createUrl && createIconType === "none") {
      const detected = detectIconFromUrl(createUrl);
      if (detected) {
        setCreateIconType("preset");
        setCreateIconValue(detected);
      }
    }
  }, [createUrl, createIconType]); // Added createIconType to dependencies to re-evaluate if type changes

  const fetchLinks = async () => {
    if (!user) return;
    try {
      const records = await pb.collection('links').getList<LinkItem>(1, 100, {
        filter: `user_id = "${user.id}" && show_on_profile=true`,
        sort: 'order,-created',
        requestKey: null,
      });
      setLinks(records.items);
    } catch (error: unknown) {
      toast.error("Failed to load links");
    } finally {
      setLinksLoading(false);
    }
  };

  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        toast.error("Avatar image must be less than 5MB");
        if (fileInputRef.current) fileInputRef.current.value = "";
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => setImageToCrop(reader.result as string);
      reader.readAsDataURL(file);
    }
    // Clear input so same file can be selected again
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  const onCropComplete = (croppedArea: Area, croppedAreaPixels: Area) => {
    setCroppedAreaPixels(croppedAreaPixels);
  };

  const handleApplyCrop = async () => {
    if (!imageToCrop || !croppedAreaPixels) return;
    try {
      const croppedImage = await getCroppedImg(imageToCrop, croppedAreaPixels);
      if (croppedImage) {
        setAvatarFile(croppedImage);
        setAvatarPreview(URL.createObjectURL(croppedImage)); // Show local preview
        setImageToCrop(null); // Close modal
      }
    } catch (e) {
      toast.error("Failed to crop image");
    }
  };

  const handleCancelCrop = () => {
    setImageToCrop(null);
  };

  const handleSaveProfile = async () => {
    if (!user) return;
    setProfileLoading(true);

    try {
      // Step 0: Handle username change restriction notice
      if (username !== user.username && isUsernameLocked) {
        toast.error("You cannot change your username yet. Please wait for the 21-day period to pass.");
        setProfileLoading(false);
        return;
      }

      // Step 1: Update text fields + social_links via JSON
      const updateData: Record<string, unknown> = {
        name,
        username,
        bio,
        theme,
        social_links: socialLinks,
      };

      console.log("[handleSaveProfile] Updating user metadata...", updateData);
      await pb.collection("users").update(user.id, updateData, { requestKey: null });

      // Step 2: Upload files separately
      if (avatarFile || customBgFile) {
        const fileData = new FormData();
        if (avatarFile) fileData.append("avatar", avatarFile);
        if (customBgFile) fileData.append("custom_theme_bg", customBgFile);
        await pb.collection("users").update(user.id, fileData, { requestKey: null });
      }

      // Step 3: Synchronize Regular Links
      console.log("[handleSaveProfile] Syncing regular links...");
      // Fetch currently persisted links for this user to compare
      const dbLinksResult = await pb.collection('links').getList<LinkItem>(1, 100, {
        filter: `user_id = "${user.id}"`,
        requestKey: null,
      });
      const dbLinks = dbLinksResult.items;

      // A. Identify links to DELETE (in DB but not in our current state 'links')
      const linksToDelete = dbLinks.filter(dbl => !links.find(l => l.id === dbl.id));
      for (const link of linksToDelete) {
        await pb.collection('links').delete(link.id, { requestKey: null });
      }

      // B. Identify links to CREATE or UPDATE
      for (const link of links) {
        const isNew = link.id.startsWith('temp-');

        const payload = {
          user_id: user.id,
          title: link.title,
          destination_url: link.destination_url,
          slug: link.slug,
          order: link.order,
          active: link.active,
          show_on_profile: link.show_on_profile,
          icon_type: link.icon_type,
          icon_value: link.icon_value,
          mode: link.mode || "redirect",
          size: link.size || "regular",
        };

        if (isNew) {
          await pb.collection('links').create(payload, { requestKey: null });
        } else {
          // Check if changed
          const original = dbLinks.find(dbl => dbl.id === link.id);
          if (original) {
            // Check if any visible field changed
            const fieldsToCompare = ['title', 'destination_url', 'slug', 'order', 'active', 'show_on_profile', 'icon_type', 'icon_value', 'mode', 'size'];
            const hasChanged = fieldsToCompare.some(key => (payload as unknown as Record<string, unknown>)[key] !== (original as unknown as Record<string, unknown>)[key]);
            if (hasChanged) {
              await pb.collection('links').update(link.id, payload, { requestKey: null });
            }
          }

          // Handle bg_image file upload/removal for this link
          const pendingBg = pendingBgImages[link.id];
          if (pendingBg) {
            const bgFormData = new FormData();
            if (pendingBg.remove) {
              bgFormData.append('bg_image', '');
            } else if (pendingBg.file) {
              bgFormData.append('bg_image', pendingBg.file);
            }
            await pb.collection('links').update(link.id, bgFormData, { requestKey: null });
          }
        }
      }
      setPendingBgImages({});

      setAvatarFile(null);
      setCustomBgFile(null);

      // Step 4: Refresh Auth Store to guarantee local context perfectly matches DB
      try {
        await pb.collection("users").authRefresh();
      } catch (e) {
        console.warn("Failed to refresh auth store after update", e);
      }

      toast.success("Profile saved successfully");
    } catch (error: any) {
      console.error("[handleSaveProfile] Error:", error);
      
      let detailedError = error?.message || "Unknown error";
      const responseData = error?.response?.data;
      
      if (typeof responseData === 'object' && responseData !== null) {
          if (responseData.data && typeof responseData.data === 'object' && Object.keys(responseData.data).length > 0) {
              const firstKey = Object.keys(responseData.data)[0];
              if (firstKey && responseData.data[firstKey].message) {
                  detailedError = responseData.data[firstKey].message;
              } else {
                  detailedError = responseData.message || JSON.stringify(responseData.data);
              }
          } else {
              detailedError = responseData.message || JSON.stringify(responseData);
          }
      }

      toast.error(detailedError);
    } finally {
      setProfileLoading(false);
    }
  };


  // --- LINK MANAGEMENT ---

  const handleCreateLink = async () => {
    if (!user || !createTitle.trim()) {
      toast.error("Title is required");
      return;
    }

    const urlValidation = urlSchema.safeParse(createUrl);
    if (!urlValidation.success) {
      toast.error(urlValidation.error.errors[0].message);
      return;
    }
    const validatedUrl = urlValidation.data;

    const userPlan = (user as { plan?: string })?.plan || "creator";
    if (!canUseResource(userPlan, "links", links.length)) {
      toast.error("Link limit reached. Please upgrade your plan.");
      return;
    }

    // Local only change
    const newLinks = [...links];
    const highestOrder = links.length > 0 ? Math.max(...links.map(l => l.order || 0)) : 0;
    const tempId = `temp-${Math.random().toString(36).substring(2, 9)}`;

    const newLink: LinkItem = {
      id: tempId,
      slug: Math.random().toString(36).substring(2, 8),
      destination_url: validatedUrl,
      title: createTitle,
      show_on_profile: true,
      order: highestOrder + 1,
      active: true,
      clicks_count: 0,
      created: new Date().toISOString(),
      icon_type: createIconType,
      icon_value: createIconValue,
      size: createSize,
    };

    setLinks([...links, newLink]);

    // Reset form
    setCreateTitle("");
    setCreateUrl("");
    setCreateIconType("none");
    setCreateIconValue("");
    setCreateSize("regular");
    setShowCreate(false);
    toast.info("Link added to list (unsaved)");
  };

  const handleUpdateLink = (id: string, updatedLink: LinkItem, bgImageFile: File | null, bgImageRemoved: boolean) => {
    setLinks(links.map(l => l.id === id ? updatedLink : l));
    if (bgImageFile || bgImageRemoved) {
      setPendingBgImages(prev => ({ ...prev, [id]: { file: bgImageFile, remove: bgImageRemoved } }));
    }
    toast.info("Link updated in list (unsaved)");
  };

  const handleDeleteLink = (id: string) => {
    if (!confirm("Remove this link?")) return;
    setLinks(links.filter(l => l.id !== id));
    toast.info("Link removed from list (unsaved)");
  };

  const toggleProfileVisibility = (id: string, currentStatus: boolean) => {
    setLinks(links.map((l) => (l.id === id ? { ...l, show_on_profile: !currentStatus } : l)));
  };

  const handleDragEnd = (result: DropResult) => {
    if (!result.destination) return;
    const sourceIndex = result.source.index;
    const destinationIndex = result.destination.index;
    if (sourceIndex === destinationIndex) return;

    const newLinks = Array.from(links);
    const [reorderedItem] = newLinks.splice(sourceIndex, 1);
    newLinks.splice(destinationIndex, 0, reorderedItem);

    const reorderedWithOrder = newLinks.map((link, index) => ({ ...link, order: index }));
    setLinks(reorderedWithOrder);
  };

  const activeTheme = THEMES.find(t => t.id === theme) || THEMES[0];
  const profileLinks = links.filter(l => l.active && l.show_on_profile !== false);

  const lastUsernameChange = user?.username_last_changed;
  const isUsernameLocked = (lastUsernameChange && lastUsernameChange.trim() !== "")
    ? (new Date().getTime() - new Date(lastUsernameChange).getTime()) < 21 * 24 * 60 * 60 * 1000
    : false;

  return (
    <div className="space-y-8 pb-10 overflow-visible">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold text-foreground">Link-in-Bio Profile</h1>
          <p className="text-muted-foreground text-sm mt-1">Manage your identity and links in one place</p>
        </div>
        {username ? (
          <a
            href={`/${username}`}
            target="_blank"
            rel="noopener"
            className="inline-flex items-center gap-2 text-sm text-accent hover:underline px-4 py-2 bg-accent/5 rounded-lg border border-accent/20 transition-all font-medium"
          >
            <Globe className="w-4 h-4" /> View Public Profile
          </a>
        ) : (
          <button
            disabled
            className="inline-flex items-center gap-2 text-sm text-muted-foreground px-4 py-2 bg-surface rounded-lg border border-border cursor-not-allowed font-medium"
            title="Please set a username to view your public profile"
          >
            <Globe className="w-4 h-4 opacity-50" /> Set username first
          </button>
        )}
      </div>


      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left Col: Editor */}
        <div className="lg:col-span-7 space-y-6">

          <div className="glass-card p-6 space-y-6">
            <h2 className="text-lg font-semibold flex items-center gap-2 text-white">
              <Camera className="w-5 h-5 text-accent" /> Visuals
            </h2>

            <div className="flex items-center gap-6">
              <div className="relative group cursor-pointer" onClick={() => fileInputRef.current?.click()}>
                <div className="absolute -inset-1 bg-gradient-to-tr from-accent to-accent/50 rounded-2xl blur opacity-25 group-hover:opacity-50 transition duration-500"></div>
                <div className="relative w-24 h-24 rounded-2xl bg-surface border-2 border-border overflow-hidden flex items-center justify-center">
                  {avatarPreview ? (
                    <img src={avatarPreview} alt="Avatar" className="w-full h-full object-cover object-top" />
                  ) : (
                    <User className="w-10 h-10 text-muted-foreground" />
                  )}
                  <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                    <Upload className="w-6 h-6 text-white" />
                  </div>
                </div>
                <input type="file" ref={fileInputRef} onChange={handleAvatarChange} className="hidden" accept="image/*" disabled={!canCustomize} />
              </div>
              <div className="space-y-1">
                <p className="font-medium text-white">Profile Picture</p>
                {canCustomize && (
                  <button onClick={() => fileInputRef.current?.click()} className="text-xs font-semibold text-accent hover:text-accent/80 transition-colors mt-2">
                    Upload New Image
                  </button>
                )}
              </div>
            </div>

            <div className="space-y-4 pt-2">
              <h3 className="text-sm font-medium flex items-center gap-2 text-white">
                <Palette className="w-4 h-4 text-accent" /> Profile Theme
              </h3>
              <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                {THEMES.map((t) => (
                  <button
                    key={t.id}
                    onClick={() => canCustomize && setTheme(t.id)}
                    disabled={!canCustomize}
                    className={`relative p-3 rounded-xl border text-left transition-all ${theme === t.id ? "border-accent bg-accent/5 ring-1 ring-accent/50" : "border-border bg-surface hover:border-accent/30"} ${!canCustomize ? "opacity-50 cursor-not-allowed" : ""}`}
                  >
                    <div className={`w-full h-12 rounded-lg mb-2 ${t.colors} border`} />
                    <span className="text-xs font-medium block text-white">{t.name}</span>
                    {theme === t.id && (
                      <div className="absolute top-2 right-2 w-4 h-4 rounded-full bg-accent flex items-center justify-center">
                        <Check className="w-2.5 h-2.5 text-white" />
                      </div>
                    )}
                  </button>
                ))}
              </div>

              {theme === "custom" && (
                <div className="mt-4 p-4 border border-border border-dashed rounded-xl bg-background/50 flex flex-col items-center justify-center space-y-3">
                  {customBgPreview ? (
                    <div className="relative w-full h-32 rounded-lg overflow-hidden group">
                      <img src={customBgPreview} alt="Custom Background" className="w-full h-full object-cover" />
                      <div className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                        <button type="button" onClick={() => customBgInputRef.current?.click()} className="btn-primary-glow text-xs py-1.5 px-3">
                          Change Background
                        </button>
                      </div>
                    </div>
                  ) : (
                    <>
                      <div className="w-10 h-10 rounded-full bg-accent/10 flex items-center justify-center">
                        <Upload className="w-5 h-5 text-accent" />
                      </div>
                      <div className="text-center">
                        <p className="text-sm font-medium text-white mb-1">Upload Custom Background</p>
                        <p className="text-xs text-muted-foreground">Recommended: 1080x1920 JPG or PNG</p>
                      </div>
                      <button type="button" onClick={() => customBgInputRef.current?.click()} className="btn-primary-glow text-xs py-1.5 px-3">
                        Choose File
                      </button>
                    </>
                  )}
                  <input
                    type="file"
                    ref={customBgInputRef}
                    onChange={(e) => {
                      const file = e.target.files?.[0];
                      if (file) {
                        if (file.size > 5 * 1024 * 1024) {
                            toast.error("Background image must be less than 5MB");
                            return;
                        }
                        setCustomBgFile(file);
                        const reader = new FileReader();
                        reader.onloadend = () => setCustomBgPreview(reader.result as string);
                        reader.readAsDataURL(file);
                      }
                    }}
                    className="hidden"
                    accept="image/*"
                  />
                </div>
              )}
            </div>
          </div>

          {/* Identity Section */}
          <div className="glass-card p-6 space-y-5">
            <h2 className="text-lg font-semibold flex items-center gap-2 text-white">
              <User className="w-5 h-5 text-accent" /> Identity
            </h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="text-sm font-medium text-muted-foreground mb-1 block">Display Name</label>
                <input value={name} onChange={(e) => setName(e.target.value)} disabled={!canCustomize} placeholder="Your Name" className="w-full px-4 py-2 rounded-xl bg-surface border border-border focus:outline-none input-glow focus:border-accent/50 transition-colors disabled:opacity-50" />
              </div>
              <div>
                <label className="text-sm font-medium text-muted-foreground mb-1 block">Username</label>
                <div className="space-y-1.5">
                  <input
                    value={username}
                    onChange={(e) => setUsername(e.target.value.toLowerCase().replace(/[^a-z0-9_-]/g, ""))}
                    disabled={!canCustomize || isUsernameLocked}
                    placeholder="username"
                    className={`w-full px-4 py-2 rounded-xl bg-surface border border-border focus:outline-none input-glow focus:border-accent/50 transition-colors disabled:opacity-50 ${isUsernameLocked ? 'cursor-not-allowed grayscale-[0.5]' : ''}`}
                  />
                  {isUsernameLocked && (
                    <div className="flex items-center gap-1.5 text-[10px] text-amber-500 font-medium px-1">
                      <Lock className="w-3 h-3" />
                      Username can be changed once every 21 days
                    </div>
                  )}
                  {!isUsernameLocked && (
                    <p className="text-[10px] text-muted-foreground px-1">You can change your username once every 21 days.</p>
                  )}
                </div>
              </div>
            </div>
            <div>
              <label className="text-sm font-medium text-muted-foreground mb-1 block">Bio</label>
              <textarea value={bio} onChange={(e) => setBio(e.target.value)} disabled={!canCustomize} placeholder="Write a short bio..." rows={2} className="w-full px-4 py-2 rounded-xl bg-surface border border-border focus:outline-none input-glow focus:border-accent/50 transition-colors resize-none disabled:opacity-50" />
            </div>
          </div>

          {/* Social Links Section */}
          <div className="glass-card p-6 space-y-5 overflow-visible">
            <div className="flex items-center justify-between">
              <h2 className="text-lg font-semibold flex items-center gap-2 text-white">
                <Globe className="w-5 h-5 text-accent" /> Social Links
                <span className="text-xs font-normal text-muted-foreground ml-1">(max 3)</span>
              </h2>
              <button
                onClick={() => {
                  if (socialLinks.length >= 3) {
                    toast.error("Maximum 3 social links allowed.");
                    return;
                  }
                  setSocialLinks([...socialLinks, { id: Math.random().toString(36).substring(2, 9), url: "", icon_type: "none", icon_value: "" }]);
                }}
                disabled={socialLinks.length >= 3}
                className={`px-3 py-1.5 rounded-lg text-sm font-medium flex items-center gap-1.5 transition-colors ${socialLinks.length >= 3 ? "bg-white/5 border border-white/10 text-muted-foreground cursor-not-allowed" : "bg-accent/10 hover:bg-accent/20 text-accent"}`}
              >
                <Plus className="w-4 h-4" /> Add Social
              </button>
            </div>

            <div className="space-y-3">
              {socialLinks.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-4 italic">No social links added yet.</p>
              ) : (
                socialLinks.map((link, idx) => (
                  <div key={link.id} className="flex flex-col gap-3 p-4 bg-surface/50 border border-border rounded-xl group animate-fade-in relative">
                    <button
                      onClick={() => setSocialLinks(socialLinks.filter(l => l.id !== link.id))}
                      className="absolute top-2 right-2 p-1.5 rounded-lg hover:bg-destructive/20 text-muted-foreground hover:text-destructive opacity-0 group-hover:opacity-100 transition-all"
                    >
                      <Trash2 className="w-3.5 h-3.5" />
                    </button>

                    <div className="flex gap-3">
                      <div className="relative">
                        <button
                          id={`social-icon-btn-${link.id}`}
                          type="button"
                          onClick={() => {
                            setSocialEditingId(socialEditingId === `social-${link.id}` ? null : `social-${link.id}`);
                          }}
                          className="h-[42px] w-[42px] bg-background border border-border rounded-xl flex items-center justify-center hover:bg-surface-hover transition-colors overflow-hidden"
                        >
                          <IconRenderer type={link.icon_type} value={link.icon_value} className="w-5 h-5 text-accent" />
                        </button>

                        {socialEditingId === `social-${link.id}` && (
                          <IconPicker
                            currentType={link.icon_type}
                            currentValue={link.icon_value}
                            anchorRef={{ current: document.getElementById(`social-icon-btn-${link.id}`) } as React.RefObject<HTMLElement>}
                            onChange={(type, value) => {
                              const newLinks = [...socialLinks];
                              newLinks[idx] = { ...newLinks[idx], icon_type: type, icon_value: value };
                              setSocialLinks(newLinks);
                              setSocialEditingId(null);
                            }}
                            onClose={() => setSocialEditingId(null)}
                          />
                        )}
                      </div>

                      <div className="flex-1 space-y-2">
                        <input
                          value={link.url}
                          onChange={(e) => {
                            const newLinks = [...socialLinks];
                            const url = e.target.value;
                            let icon_type = link.icon_type;
                            let icon_value = link.icon_value;

                            // Auto-detect icon if none is selected
                            if (link.icon_type === "none" || !link.icon_value) {
                              const detected = detectIconFromUrl(url);
                              if (detected) {
                                icon_type = "preset";
                                icon_value = detected;
                              }
                            }

                            newLinks[idx] = { ...newLinks[idx], url, icon_type, icon_value };
                            setSocialLinks(newLinks);
                          }}
                          placeholder="Social URL (e.g. instagram.com/user)"
                          className="w-full px-4 py-2 rounded-xl bg-background border border-border text-sm focus:outline-none focus:border-accent/50"
                        />
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Links Section */}
          <div className="bg-card/60 border border-border rounded-2xl p-6 space-y-5">
            <div className="flex items-center justify-between">
              <h2 className="text-lg font-semibold flex items-center gap-2 text-white">
                <Globe className="w-5 h-5 text-accent" /> Links
              </h2>
              {!showCreate && (
                <button
                  onClick={() => setShowCreate(true)}
                  className="px-3 py-1.5 rounded-lg bg-accent/10 hover:bg-accent/20 text-accent text-sm font-medium flex items-center gap-1.5 transition-colors"
                >
                  <Plus className="w-4 h-4" /> Add Link
                </button>
              )}
            </div>

            {/* Inline Create Form */}
            {showCreate && (
              <div className="bg-surface p-4 rounded-xl border border-accent/30 space-y-3 animate-fade-in text-white">
                <div className="flex justify-between items-center mb-1">
                  <h3 className="text-sm font-medium text-white">New Link</h3>
                  <button onClick={() => {
                    setShowCreate(false);
                    setCreateSize("regular");
                  }} className="text-muted-foreground hover:text-white"><X className="w-4 h-4" /></button>
                </div>
                <div>
                  <input value={createTitle} onChange={(e) => setCreateTitle(e.target.value)} placeholder="Title (e.g. My Website)" className="w-full px-3 py-2 rounded-lg bg-background border border-border text-sm mb-2 text-white" />
                  <div className="flex gap-2 mb-2">
                    <div className="relative">
                      <button
                        id="create-link-icon-btn"
                        type="button"
                        onClick={() => setShowIconPicker(!showIconPicker)}
                        className="w-[38px] h-[38px] bg-background border border-border rounded-lg flex items-center justify-center shrink-0 overflow-hidden hover:bg-surface-hover transition-colors"
                      >
                        <IconRenderer type={createIconType} value={createIconValue} className="w-4 h-4 text-muted-foreground" />
                      </button>
                      {showIconPicker && (
                        <IconPicker
                          currentType={createIconType}
                          currentValue={createIconValue}
                          anchorRef={{ current: document.getElementById("create-link-icon-btn") } as React.RefObject<HTMLElement>}
                          onChange={(type, value) => {
                            setCreateIconType(type);
                            setCreateIconValue(value);
                            setShowIconPicker(false);
                          }}
                          onClose={() => setShowIconPicker(false)}
                        />
                      )}
                    </div>
                    <input value={createUrl} onChange={(e) => setCreateUrl(e.target.value)} placeholder="URL (https://...)" type="url" className="flex-1 px-3 py-2 rounded-lg bg-background border border-border text-sm text-white" />
                  </div>

                  {/* Size Selection */}
                  <div className="space-y-2 mt-3">
                    <label className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest px-1">Display Size</label>
                    <div className="flex gap-2">
                      <button
                        onClick={() => setCreateSize("regular")}
                        className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg border text-xs font-semibold transition-all ${createSize === "regular" ? "bg-accent/10 border-accent/50 text-accent" : "bg-background border-border text-muted-foreground hover:border-accent/30"}`}
                      >
                        Regular
                      </button>
                      <button
                        onClick={() => setCreateSize("large")}
                        className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg border text-xs font-semibold transition-all ${createSize === "large" ? "bg-accent/10 border-accent/50 text-accent" : "bg-background border-border text-muted-foreground hover:border-accent/30"}`}
                      >
                        Large
                      </button>
                    </div>
                  </div>
                </div>
                <div className="flex items-center justify-between pt-2 border-t border-white/5">
                  <div className="flex items-center gap-1.5 text-xs text-muted-foreground bg-accent/5 px-2 py-1 rounded-md border border-accent/10">
                    <Check className="w-3 h-3 text-accent" />
                    Automatically added to profile
                  </div>
                  <button
                    onClick={handleCreateLink}
                    disabled={createLoading || !createUrl || !createTitle}
                    className="btn-primary-glow !py-1.5 !px-4 text-sm flex items-center gap-2 disabled:opacity-50"
                  >
                    {createLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : "Save Link"}
                  </button>
                </div>
              </div>
            )}

            {/* Links List */}
            {linksLoading ? (
              <div className="flex justify-center py-8"><Loader2 className="w-6 h-6 animate-spin text-accent" /></div>
            ) : links.length === 0 && !showCreate ? (
              <div className="text-center py-6 text-muted-foreground text-sm">No links added yet.</div>
            ) : (
              <DragDropContext onDragEnd={handleDragEnd}>
                <Droppable droppableId="profile-links" isDropDisabled={links.length <= 1}>
                  {(provided) => (
                    <div {...provided.droppableProps} ref={provided.innerRef} className="space-y-2">
                      {links.map((link, index) => (
                        <Draggable key={link.id} draggableId={link.id} index={index} isDragDisabled={links.length <= 1}>
                          {(provided, snapshot) => (
                            <LinkItemCard
                              link={link}
                              provided={provided}
                              snapshot={snapshot}
                              onUpdate={handleUpdateLink}
                              onDelete={handleDeleteLink}
                            />
                          )}
                        </Draggable>
                      ))}
                      {provided.placeholder}
                    </div>
                  )}
                </Droppable>
              </DragDropContext>
            )}
          </div>

          <button
            onClick={handleSaveProfile}
            disabled={profileLoading}
            className="btn-primary-glow w-full flex items-center justify-center gap-2 py-3 mt-4 text-base font-bold shadow-lg shadow-accent/20 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {profileLoading ? <Loader2 className="w-5 h-5 animate-spin" /> : "Save Entire Profile"}
          </button>
        </div>

        {/* Right Col: Live Preview */}
        <div className="lg:col-span-5 relative hidden md:block">
          <div className="sticky top-24 flex flex-col items-center">
            <div className="mb-4 flex items-center gap-2 text-sm text-muted-foreground">
              <Smartphone className="w-4 h-4" /> Live Mobile Preview
            </div>

            {/* Phone Frame */}
            <div className="relative w-[320px] h-[640px] rounded-[52px] border-[10px] border-surface p-1 shadow-2xl overflow-hidden shadow-accent/20 bg-background/50">
              <div className="absolute top-0 left-1/2 -translate-x-1/2 w-24 h-5 bg-surface rounded-b-2xl z-20" />

              {/* Profile Inner Content (Dynamic Mockup) */}
              <div
                className="w-full h-full bg-black relative flex flex-col no-scrollbar rounded-[40px] overflow-hidden"
              >
                <div className="flex flex-col flex-1 overflow-y-auto no-scrollbar relative z-10 pb-10">
                  {/* Top Header with Avatar and Fade */}
                  <div className="relative aspect-[10/8] w-full overflow-hidden shrink-0">
                    {avatarPreview ? (
                      <img src={avatarPreview} alt="Preview" className="w-full h-full object-cover object-top" />
                    ) : (
                      <div className="w-full h-full bg-surface flex items-center justify-center">
                        <span className="text-5xl font-bold bg-gradient-to-br from-white to-white/30 bg-clip-text text-transparent">{name.charAt(0) || "?"}</span>
                      </div>
                    )}
                    <div className="absolute bottom-0 w-full h-1/2 bg-gradient-to-t from-black via-black/40 to-transparent transition-all duration-700" />
                  </div>

                  {/* Profile Content */}
                  <div className="px-5 -mt-10 relative">
                    <div className="text-center space-y-1">
                      <h4 className="text-2xl font-black tracking-tight text-white drop-shadow-lg">{name || "Your Name"}</h4>
                      <p className="text-muted-foreground text-xs font-medium tracking-wide">@{username || "username"}</p>
                    </div>

                    {/* Social Icons Preview */}
                    {socialLinks.length > 0 && (
                      <div className="flex items-center justify-center gap-2 mt-3 flex-wrap">
                        {socialLinks.map(link => (
                          <div key={link.id} className="w-8 h-8 rounded-xl bg-white/5 border border-white/10 flex items-center justify-center">
                            <IconRenderer type={link.icon_type} value={link.icon_value} className="w-4 h-4 text-white/80" />
                          </div>
                        ))}
                      </div>
                    )}

                    {/* Bio */}
                    <div className="mt-2 text-center">
                      <p className="text-white text-xs leading-relaxed max-w-[240px] mx-auto">{bio || "Your bio will appear here..."}</p>
                    </div>

                    {/* Dynamic Links */}
                    <div className="w-full mt-5 space-y-3">
                      {profileLinks.length === 0 ? (
                        <div className="text-center text-white/40 text-sm italic mt-10">No visible links yet.</div>
                      ) : (
                        profileLinks.map((link) => {
                          const bgImageUrl = (link.size === 'large' && link.bg_image)
                            ? pb.files.getUrl(link, link.bg_image)
                            : null;

                          return (
                            <div key={link.id} className={`w-full rounded-2xl bg-[#111] border border-white/5 hover:bg-[#161616] hover:border-white/20 transition-all group cursor-pointer shadow-lg shadow-black/5 relative overflow-hidden flex ${link.size === 'large' ? 'flex-col p-3 aspect-[10/6] sm:aspect-[10/5.4]' : 'h-[40px] items-center justify-center'}`}>

                              {/* Large Size Background Map */}
                              {bgImageUrl && (
                                <>
                                  <img
                                    src={bgImageUrl}
                                    alt="Background"
                                    className="absolute inset-0 w-full h-full object-cover z-0 transition-transform duration-700 group-hover:scale-105"
                                  />
                                  <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/40 to-black/20 z-0" />
                                </>
                              )}

                              <div className={`relative z-10 flex w-full ${link.size === 'large' ? 'h-full flex-col justify-between items-start' : 'items-center justify-center'}`}>
                                <div className={`${link.size === 'large' ? 'shrink-0 self-start' : 'absolute left-0 shrink-0 ml-0'}`}>
                                  <div className={`${link.size === 'large' ? 'w-8 h-8 rounded-xl bg-white/10 backdrop-blur-md overflow-hidden shadow-lg' : 'w-11 h-11 rounded-xl overflow-hidden'} flex items-center justify-center`}>
                                    <IconRenderer type={link.icon_type} value={link.icon_value} url={link.destination_url} className={`${link.size === 'large' ? 'w-4 h-4' : 'w-5 h-5'} text-white/90 drop-shadow-md`} />
                                  </div>
                                </div>
                                <div className={`${link.size === 'large' ? 'mt-auto text-center w-full px-10' : 'text-center px-10'}`}>
                                  <span className={`font-bold text-white group-hover:scale-[1.02] transition-transform block uppercase tracking-wider ${link.size === 'large' ? 'text-sm drop-shadow-lg' : 'text-xs'}`}>{link.title || "Untitled Link"}</span>
                                </div>
                              </div>
                            </div>
                          );
                        })
                      )}
                    </div>

                    {!checkPlan(userPlan, "remove_branding") && (
                      <div className="mt-auto pt-10 pb-2 flex flex-col items-center gap-1.5 shrink-0">
                        <div className="flex items-center gap-1.5 grayscale mix-blend-screen opacity-50">
                          <img src="/logo.webp" alt="Linktery" className="h-7 w-auto" />
                          <span className="text-[9px] font-bold tracking-widest uppercase text-white translate-y-[0.5px]">Linktery</span>
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
      {/* Cropping Modal */}
      {
        imageToCrop && (
          <div className="fixed inset-0 z-50 bg-background/90 backdrop-blur-sm flex items-center justify-center p-4">
            <div className="bg-surface border border-border rounded-2xl p-6 w-full max-w-md shadow-2xl flex flex-col items-center">
              <h3 className="text-lg font-bold text-foreground mb-4">Crop Avatar</h3>

              <div className="relative w-full h-64 bg-black/20 rounded-xl overflow-hidden mb-6">
                <Cropper
                  image={imageToCrop}
                  crop={crop}
                  zoom={zoom}
                  aspect={1}
                  cropShape="rect"
                  showGrid={false}
                  onCropChange={setCrop}
                  onCropComplete={onCropComplete}
                  onZoomChange={setZoom}
                />
              </div>

              <div className="w-full flex items-center gap-4 mb-6">
                <span className="text-muted-foreground text-sm">Zoom</span>
                <input
                  type="range"
                  value={zoom}
                  min={1}
                  max={3}
                  step={0.1}
                  onChange={(e) => setZoom(Number(e.target.value))}
                  className="flex-1 accent-accent"
                />
              </div>

              <div className="flex gap-3 w-full">
                <button
                  onClick={handleCancelCrop}
                  className="flex-1 py-2 rounded-xl text-muted-foreground font-medium hover:bg-surface-hover transition-colors"
                  disabled={profileLoading} // Reuse creating status optionally if busy
                >
                  Cancel
                </button>
                <button
                  onClick={handleApplyCrop}
                  className="flex-1 py-2 btn-primary-glow font-medium"
                >
                  Apply Crop
                </button>
              </div>
            </div>
          </div>
        )
      }
    </div >
  );
}

import { useState, useEffect, useMemo } from "react";
import { pb } from "@/lib/pocketbase";
import {
    Users, Link as LinkIcon, Activity, TrendingUp, ChevronLeft,
    ArrowUpRight, ArrowDownRight, Zap, Target, MousePointer2,
    AlertCircle, Lightbulb, ShieldCheck, Globe, Clock, History
} from "lucide-react";
import {
    AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip,
    ResponsiveContainer, BarChart, Bar, Cell, PieChart, Pie
} from "recharts";
import { useNavigate } from "react-router-dom";
import { format, subDays, startOfDay, isAfter, subHours, differenceInDays } from "date-fns";
import { toast } from "sonner";

interface DashboardStats {
    totalUsers: number;
    newUsers24h: number;
    newUsers7d: number;
    dau: number;
    wau: number;
    totalLinks: number;
    totalRevenue: number;
    mrr: number;
    conversionRate: number;
    churnRate: number;
    avgLinksPerUser: number;
    trends: {
        users: number;
        revenue: number;
        dau: number;
        conversion: number;
    }
}

const COLORS = ['#10b981', '#f59e0b', '#8b5cf6', '#ef4444', '#3b82f6'];

export default function AdminOverview() {
    const navigate = useNavigate();
    const [timeRange, setTimeRange] = useState<"24h" | "7d" | "30d" | "all">("7d");
    const [loading, setLoading] = useState(true);
    const [stats, setStats] = useState<DashboardStats>({
        totalUsers: 0,
        newUsers24h: 0,
        newUsers7d: 0,
        dau: 0,
        wau: 0,
        totalLinks: 0,
        totalRevenue: 0,
        mrr: 0,
        conversionRate: 0,
        churnRate: 0,
        avgLinksPerUser: 0,
        trends: { users: 0, revenue: 0, dau: 0, conversion: 0 }
    });

    const [growthData, setGrowthData] = useState<any[]>([]);
    const [planData, setPlanData] = useState<any[]>([]);
    const [trafficData, setTrafficData] = useState<any[]>([]);
    const [conversionEvents, setConversionEvents] = useState<any[]>([]);
    const [pulseEvents, setPulseEvents] = useState<any[]>([]);
    const [systemHealth, setSystemHealth] = useState({
        errorRate: 0,
        avgLatencyp95: 0,
        alerts: [] as string[]
    });

    useEffect(() => {
        fetchDashboardData();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [timeRange]);

    const fetchDashboardData = async () => {
        setLoading(true);
        try {
            // 1. Fetch live telemetry
            const sinceDate = format(subDays(new Date(), 90), "yyyy-MM-dd HH:mm:ss");

            const [users, links, billing, clicks, analytics, logs] = await Promise.all([
                pb.collection("users").getFullList({ sort: "-created", requestKey: null }),
                pb.collection("links").getFullList({ requestKey: null }),
                pb.collection("billing").getFullList({ requestKey: null }),
                pb.collection("clicks").getFullList({ requestKey: null }),
                pb.collection("analytics_events").getFullList({ sort: "-created", filter: `created > "${sinceDate}"`, requestKey: null }),
                pb.collection("system_logs").getFullList({ sort: "-created", filter: `created > "${sinceDate}"`, requestKey: null })
            ]);

            const now = new Date();
            const last24h = subHours(now, 24);
            const last7d = subDays(now, 7);
            const prev7d = subDays(now, 14);

            // Metrics Calculation
            const paidUsers = users.filter(u => u.plan !== 'creator' && u.plan_status === 'active');
            const totalRevenue = billing.filter(b => b.status === 'success').reduce((acc, b) => acc + (b.amount || 0), 0);
            const mrr = paidUsers.reduce((acc, u) => acc + (u.plan === 'pro' ? 9.99 : u.plan === 'agency' ? 29.99 : 0), 0);

            // DAU/WAU (distinct users in events)
            const dauUsers = new Set(analytics.filter(e => isAfter(new Date(e.created), last24h)).map(e => e.user_id));
            const wauUsers = new Set(analytics.filter(e => isAfter(new Date(e.created), last7d)).map(e => e.user_id));

            // Previous period activity for trends
            const prevDauUsers = new Set(analytics.filter(e => {
                const d = new Date(e.created);
                return isAfter(d, subHours(now, 48)) && !isAfter(d, last24h);
            }).map(e => e.user_id));

            // Trend helper
            const getTrend = (current: number, previous: number) => {
                if (previous === 0) return current > 0 ? 100 : 0;
                return Math.round(((current - previous) / previous) * 100);
            };

            const currentUsers = users.filter(u => isAfter(new Date(u.created), last7d)).length;
            const previousUsers = users.filter(u => isAfter(new Date(u.created), prev7d) && !isAfter(new Date(u.created), last7d)).length;

            const currentRev = billing.filter(b => b.status === 'success' && isAfter(new Date(b.created), last7d)).reduce((acc, b) => acc + b.amount, 0);
            const previousRev = billing.filter(b => b.status === 'success' && isAfter(new Date(b.created), prev7d) && !isAfter(new Date(b.created), last7d)).reduce((acc, b) => acc + b.amount, 0);

            // Churn calculation: cancelled plans in last 30 days
            const cancelledLast30 = billing.filter(b => (b.status === 'refunded' || b.status === 'cancelled') && isAfter(new Date(b.created), subDays(now, 30))).length;
            const churnRate = paidUsers.length > 0 ? (cancelledLast30 / paidUsers.length) * 100 : 0;

            const convRate = users.length > 0 ? (paidUsers.length / users.length) * 100 : 0;
            const prevConvRate = (users.length - currentUsers) > 0 ? ((paidUsers.length - billing.filter(b => isAfter(new Date(b.created), last7d)).length) / (users.length - currentUsers)) * 100 : 0;

            setStats({
                totalUsers: users.length,
                newUsers24h: users.filter(u => isAfter(new Date(u.created), last24h)).length,
                newUsers7d: currentUsers,
                dau: dauUsers.size,
                wau: wauUsers.size,
                totalLinks: links.length,
                totalRevenue,
                mrr,
                conversionRate: convRate,
                churnRate,
                avgLinksPerUser: users.length > 0 ? links.length / users.length : 0,
                trends: {
                    users: getTrend(currentUsers, previousUsers),
                    revenue: getTrend(currentRev, previousRev),
                    dau: getTrend(dauUsers.size, prevDauUsers.size),
                    conversion: getTrend(convRate, prevConvRate)
                }
            });

            // Pulse list: Last 10 events
            setPulseEvents(analytics.filter(e => e.event_name !== 'active_session').slice(0, 10));

            // System Health calculation from logs
            const totalLogs24h = logs.filter(l => isAfter(new Date(l.created), last24h)).length;
            const errorLogs24h = logs.filter(l => l.level === 'error' && isAfter(new Date(l.created), last24h)).length;
            const errorRate = totalLogs24h >= 10 ? (errorLogs24h / totalLogs24h) * 100 : 0;

            // Extract p95 latency if available in metadata/context
            const latencies = logs.filter(l => l.metadata?.latency).map(l => l.metadata.latency);
            const p95Latency = latencies.length > 0 ? latencies.sort((a, b) => a - b)[Math.floor(latencies.length * 0.95)] : 0;

            const alerts = [];
            if (errorRate > 10 && totalLogs24h >= 20) alerts.push("High error rate detected ( > 10%). Check logs for API instability.");
            if (dauUsers.size < (wauUsers.size * 0.1)) alerts.push("Low stickiness (DAU/WAU < 10%). Onboarding friction suspected.");
            if (churnRate > 10) alerts.push("Critical churn rate alert. Subscription cancellations have spiked.");

            setSystemHealth({
                errorRate: parseFloat(errorRate.toFixed(2)),
                avgLatencyp95: p95Latency || 0,
                alerts
            });

            // Growth Chart Generation
            const chartPoints = [];
            const daysToFetch = timeRange === '24h' ? 1 : timeRange === '7d' ? 7 : timeRange === '30d' ? 30 : 90;

            for (let i = daysToFetch - 1; i >= 0; i--) {
                const day = subDays(now, i);
                const dayStr = format(day, timeRange === '24h' ? 'HH:00' : 'MMM dd');

                chartPoints.push({
                    name: dayStr,
                    users: users.filter(u => differenceInDays(now, new Date(u.created)) <= i).length,
                    revenue: billing.filter(b => b.status === 'success' && differenceInDays(now, new Date(b.created)) <= i).reduce((acc, b) => acc + (b.amount || 0), 0)
                });
            }
            setGrowthData(chartPoints);

            // Plan Pie Chart
            setPlanData([
                { name: 'Creator', value: users.filter(u => u.plan === 'creator').length },
                { name: 'Pro', value: users.filter(u => u.plan === 'pro').length },
                { name: 'Agency', value: users.filter(u => u.plan === 'agency').length },
            ]);

            // Traffic Data
            const countries: Record<string, number> = {};
            clicks.forEach(c => { if (c.country) countries[c.country] = (countries[c.country] || 0) + 1 });
            setTrafficData(Object.entries(countries).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 5));

            // Funnel Stats
            setConversionEvents([
                { name: 'Visitors', value: clicks.length, color: '#3b82f6' },
                { name: 'Signups', value: users.length, color: '#10b981' },
                { name: 'Active', value: wauUsers.size, color: '#f59e0b' },
                { name: 'Paid', value: paidUsers.length, color: '#8b5cf6' },
            ]);

        } catch (err) {
            console.error("Dashboard Fetch Error:", err);
            toast.error("Telemetry failure. Real-time monitoring disrupted.");
        } finally {
            setLoading(false);
        }
    };

    const KPIBadge = ({ label, value, trend, isCurrency = false }: any) => (
        <div className="bg-surface border border-border rounded-2xl p-5 relative overflow-hidden group hover:border-accent/40 transition-colors">
            <div className="flex justify-between items-start mb-2">
                <span className="text-sm font-medium text-muted-foreground uppercase tracking-wider">{label}</span>
                {trend !== undefined && trend !== 0 && (
                    <span className={`flex items-center text-xs font-bold px-2 py-1 rounded-full ${trend >= 0 ? 'bg-accent/10 text-accent' : 'bg-red-500/10 text-red-500'}`}>
                        {trend >= 0 ? <ArrowUpRight className="w-3 h-3 mr-0.5" /> : <ArrowDownRight className="w-3 h-3 mr-0.5" />}
                        {Math.abs(trend)}%
                    </span>
                )}
            </div>
            <div className="text-3xl font-black text-white">
                {isCurrency ? `$${value?.toLocaleString()}` : value?.toLocaleString()}
            </div>
            <div className="mt-2 flex items-center gap-2">
                <div className="w-full h-1 bg-background rounded-full overflow-hidden">
                    <div className="h-full bg-accent rounded-full opacity-30" style={{ width: '65%' }} />
                </div>
            </div>
        </div>
    );

    const dynamicInsights = useMemo(() => {
        const list = [];
        if (stats.trends.users > 10) list.push(`Viral growth detected: New signups up ${stats.trends.users}% this period.`);
        if (stats.churnRate > 5) list.push(`Revenue alert: Churn is ${stats.churnRate.toFixed(1)}%. Check retention loops.`);
        if (stats.avgLinksPerUser < 1.5) list.push("Low utilization: Users create < 2 links. Consider educational onboarding.");
        if (systemHealth.errorRate < 0.5 && systemHealth.avgLatencyp95 < 200) list.push("Infrastructure health is optimal. System scaling cleanly.");
        if (list.length === 0) list.push("Metrics are within expected baseline ranges.", "Monitoring normal user behavior patterns.");
        return list;
    }, [stats, systemHealth]);

    if (loading) return (
        <div className="min-h-[80vh] flex flex-col items-center justify-center gap-4">
            <div className="w-12 h-12 border-4 border-accent border-t-transparent rounded-full animate-spin" />
            <p className="text-muted-foreground animate-pulse font-medium">Synthesizing real-time analytics...</p>
        </div>
    );

    return (
        <div className="max-w-7xl mx-auto space-y-8 py-8 px-4 sm:px-6">
            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                <div className="space-y-1">
                    <div className="flex items-center gap-3">
                        <button onClick={() => navigate('/dashboard')} className="p-2 hover:bg-surface rounded-xl transition-colors">
                            <ChevronLeft className="w-6 h-6 text-muted-foreground" />
                        </button>
                        <h1 className="text-4xl font-black tracking-tight text-white flex items-center gap-4">
                            Business Overview <Zap className="w-8 h-8 text-accent fill-accent/20" />
                        </h1>
                    </div>
                    <p className="text-lg text-muted-foreground ml-11">Live platform telemetry and business unit performance.</p>
                </div>

                <div className="flex p-1.5 bg-surface border border-border rounded-2xl shadow-xl ml-11 md:ml-0">
                    {["24h", "7d", "30d", "all"].map(tr => (
                        <button
                            key={tr}
                            onClick={() => setTimeRange(tr as any)}
                            className={`px-5 py-2 text-sm font-bold rounded-xl transition-all ${timeRange === tr ? "bg-accent text-black shadow-lg shadow-accent/20" : "text-muted-foreground hover:text-white"}`}
                        >
                            {tr.toUpperCase()}
                        </button>
                    ))}
                </div>
            </div>

            {/* Alerts Block */}
            {systemHealth.alerts.length > 0 && (
                <div className="grid grid-cols-1 gap-4">
                    {systemHealth.alerts.map((alert, i) => (
                        <div key={i} className="flex items-center gap-4 p-4 bg-red-500/10 border border-red-500/20 rounded-2xl animate-in fade-in slide-in-from-top-4">
                            <AlertCircle className="w-6 h-6 text-red-500 shrink-0" />
                            <p className="text-red-200 font-medium">{alert}</p>
                            <button className="ml-auto text-xs font-bold text-red-500 hover:underline uppercase">Investigate</button>
                        </div>
                    ))}
                </div>
            )}

            {/* KPI Section */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                <KPIBadge label="Total Users" value={stats.totalUsers} trend={stats.trends.users} />
                <KPIBadge label="Estimated MRR" value={stats.mrr} trend={stats.trends.revenue} isCurrency={true} />
                <KPIBadge label="Active (DAU/WAU)" value={`${stats.dau} / ${stats.wau}`} trend={stats.trends.dau} />
                <KPIBadge label="Conv. Rate" value={`${stats.conversionRate.toFixed(1)}%`} trend={stats.trends.conversion} />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
                {/* Main Growth Chart */}
                <div className="lg:col-span-8 space-y-8">
                    <div className="bg-surface border border-border rounded-3xl p-8 shadow-2xl relative overflow-hidden group">
                        <div className="absolute top-0 right-0 p-8 opacity-5">
                            <TrendingUp className="w-48 h-48 text-accent" />
                        </div>
                        <div className="flex items-center justify-between mb-8">
                            <h2 className="text-2xl font-bold flex items-center gap-3">
                                Platform Growth <ArrowUpRight className="w-6 h-6 text-accent" />
                            </h2>
                            <div className="flex items-center gap-4">
                                <span className="flex items-center gap-2 text-xs font-bold text-muted-foreground">
                                    <div className="w-3 h-3 rounded-full bg-accent" /> Users
                                </span>
                                <span className="flex items-center gap-2 text-xs font-bold text-muted-foreground">
                                    <div className="w-3 h-3 rounded-full bg-purple-500" /> Revenue
                                </span>
                            </div>
                        </div>
                        <div className="h-[400px]">
                            <ResponsiveContainer width="100%" height="100%">
                                <AreaChart data={growthData}>
                                    <defs>
                                        <linearGradient id="colorUsers" x1="0" y1="0" x2="0" y2="1">
                                            <stop offset="5%" stopColor="#10b981" stopOpacity={0.2} />
                                            <stop offset="95%" stopColor="#10b981" stopOpacity={0} />
                                        </linearGradient>
                                    </defs>
                                    <CartesianGrid strokeDasharray="3 3" stroke="#ffffff08" vertical={false} />
                                    <XAxis dataKey="name" stroke="#666" fontSize={12} tickLine={false} axisLine={false} />
                                    <YAxis stroke="#666" fontSize={12} tickLine={false} axisLine={false} />
                                    <RechartsTooltip
                                        contentStyle={{ backgroundColor: '#000', borderRadius: '16px', border: '1px solid #333' }}
                                        cursor={{ stroke: '#10b981', strokeWidth: 2 }}
                                    />
                                    <Area dataKey="users" stroke="#10b981" strokeWidth={4} fill="url(#colorUsers)" />
                                    <Area dataKey="revenue" stroke="#8b5cf6" strokeWidth={4} fill="transparent" />
                                </AreaChart>
                            </ResponsiveContainer>
                        </div>
                    </div>

                    {/* Funnel & Traffic */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="bg-surface border border-border rounded-3xl p-8 shadow-xl">
                            <h2 className="text-xl font-bold mb-6 flex items-center gap-3">
                                Acquisition Funnel <Target className="w-5 h-5 text-blue-500" />
                            </h2>
                            <div className="space-y-6">
                                {conversionEvents.map((step, i) => (
                                    <div key={i} className="space-y-2">
                                        <div className="flex justify-between items-end">
                                            <span className="text-sm font-bold text-muted-foreground">{step.name}</span>
                                            <span className="text-lg font-black">{step.value.toLocaleString()}</span>
                                        </div>
                                        <div className="h-4 w-full bg-background rounded-full overflow-hidden border border-white/5">
                                            <div
                                                className="h-full rounded-full transition-all duration-1000 ease-out"
                                                style={{ width: `${(step.value / (conversionEvents[0].value || 1)) * 100}%`, backgroundColor: step.color }}
                                            />
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>

                        <div className="bg-surface border border-border rounded-3xl p-8 shadow-xl">
                            <h2 className="text-xl font-bold mb-6 flex items-center gap-3">
                                Top Geographies <Globe className="w-5 h-5 text-purple-500" />
                            </h2>
                            <div className="space-y-4">
                                {trafficData.length > 0 ? trafficData.map((item, i) => (
                                    <div key={i} className="flex items-center justify-between p-3 bg-background/50 rounded-2xl border border-white/5 hover:border-white/10 transition-colors">
                                        <div className="flex items-center gap-3">
                                            <div className="w-8 h-8 rounded-lg bg-surface flex items-center justify-center font-bold text-xs text-muted-foreground border border-white/5">
                                                {i + 1}
                                            </div>
                                            <span className="font-bold text-white uppercase tracking-wider text-sm">{item.name}</span>
                                        </div>
                                        <span className="font-medium text-accent">{item.value.toLocaleString()} clicks</span>
                                    </div>
                                )) : (
                                    <p className="text-sm text-muted-foreground text-center py-10 italic">Awaiting international telemetry...</p>
                                )}
                            </div>
                        </div>
                    </div>
                </div>

                {/* Sidebar: Plans, Health, Insights */}
                <div className="lg:col-span-4 space-y-8">
                    {/* Plan Distribution */}
                    <div className="bg-surface border border-border rounded-3xl p-8 shadow-xl">
                        <h2 className="text-xl font-bold mb-8">Revenue Sources</h2>
                        <div className="h-64">
                            <ResponsiveContainer width="100%" height="100%">
                                <PieChart>
                                    <Pie data={planData} innerRadius={60} outerRadius={85} paddingAngle={10} dataKey="value">
                                        {planData.map((entry, index) => (
                                            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                        ))}
                                    </Pie>
                                    <RechartsTooltip />
                                </PieChart>
                            </ResponsiveContainer>
                        </div>
                        <div className="mt-8 space-y-4">
                            {planData.map((p, i) => (
                                <div key={i} className="flex items-center justify-between">
                                    <div className="flex items-center gap-2">
                                        <div className="w-3 h-3 rounded-full" style={{ backgroundColor: COLORS[i] }} />
                                        <span className="text-sm font-medium text-muted-foreground">{p.name}</span>
                                    </div>
                                    <span className="font-bold text-white">{stats.totalUsers > 0 ? ((p.value / stats.totalUsers) * 100).toFixed(0) : 0}%</span>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* System Health Block */}
                    <div className="bg-surface border border-border rounded-3xl p-8 shadow-xl space-y-6">
                        <h2 className="text-xl font-bold flex items-center gap-3">
                            System Health <ShieldCheck className="w-5 h-5 text-accent" />
                        </h2>
                        <div className="space-y-6">
                            <div className="flex items-center justify-between">
                                <div className="space-y-1">
                                    <p className="text-sm font-medium text-muted-foreground">Error Rate</p>
                                    <p className="text-2xl font-black text-white">{systemHealth.errorRate}%</p>
                                </div>
                                <Activity className={`w-8 h-8 ${systemHealth.errorRate > 1 ? 'text-red-500' : 'text-accent'}`} />
                            </div>
                            <div className="flex items-center justify-between">
                                <div className="space-y-1">
                                    <p className="text-sm font-medium text-muted-foreground">p95 Latency</p>
                                    <p className="text-2xl font-black text-white">{systemHealth.avgLatencyp95}ms</p>
                                </div>
                                <Clock className="w-8 h-8 text-blue-500" />
                            </div>
                        </div>
                    </div>

                    {/* Smart Insights */}
                    <div className="bg-accent/5 border border-accent/20 rounded-3xl p-8 shadow-xl relative overflow-hidden group">
                        <div className="absolute top-0 right-0 p-4 opacity-10">
                            <Lightbulb className="w-24 h-24 text-accent" />
                        </div>
                        <h2 className="text-xl font-bold text-accent mb-6 flex items-center gap-3">
                            Smart Insights <ArrowUpRight className="w-5 h-5 text-accent" />
                        </h2>
                        <div className="space-y-4">
                            {dynamicInsights.map((insight, i) => (
                                <p key={i} className="text-sm text-accent/80 font-medium leading-relaxed">
                                    тАв {insight}
                                </p>
                            ))}
                        </div>
                        <button className="mt-8 w-full py-3 bg-accent text-black font-black rounded-xl text-sm uppercase tracking-widest hover:scale-[1.02] active:scale-[0.98] transition-all">
                            Generate Report
                        </button>
                    </div>
                </div>
            </div>

            {/* Recent Activity Mini-List */}
            <div className="bg-surface border border-border rounded-3xl p-8 shadow-xl">
                <div className="flex items-center justify-between mb-8">
                    <h2 className="text-2xl font-black text-white flex items-center gap-3">
                        Real-Time Pulse <History className="w-6 h-6 text-accent" />
                    </h2>
                    <button className="text-sm font-bold text-accent hover:underline">View All Logs</button>
                </div>
                <div className="space-y-4">
                    {pulseEvents.length > 0 ? pulseEvents.map((event, i) => (
                        <div key={i} className="flex items-center gap-4 p-4 bg-background/30 rounded-2xl border border-white/5 group hover:border-accent/30 transition-all">
                            <div className="w-10 h-10 rounded-full bg-accent/10 flex items-center justify-center">
                                <Activity className="w-5 h-5 text-accent" />
                            </div>
                            <div className="flex-1">
                                <p className="text-sm font-bold text-white uppercase">{event.event_name.replace('_', ' ')} <span className="text-muted-foreground ml-2 text-[10px]">#{event.id}</span></p>
                                <p className="text-xs text-muted-foreground">{format(new Date(event.created), 'HH:mm:ss')} тАв Event ID: {event.id}</p>
                            </div>
                            <MousePointer2 className="w-4 h-4 text-muted-foreground opacity-0 group-hover:opacity-100 transition-opacity" />
                        </div>
                    )) : (
                        <div className="text-center py-10">
                            <Activity className="w-12 h-12 text-muted-foreground mx-auto mb-4 opacity-20" />
                            <p className="text-sm text-muted-foreground italic">Heartbeat active. Waiting for system events...</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { pb } from "@/lib/pocketbase";
import {
    ChevronLeft,
    User,
    BarChart3,
    Link as LinkIcon,
    ShieldAlert,
    CreditCard,
    Settings,
    Check,
    Ban,
    ExternalLink,
    MapPin,
    Smartphone
} from "lucide-react";
import { toast } from "sonner";
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, ResponsiveContainer } from "recharts";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";

interface AdminUser {
    id: string;
    email: string;
    name: string;
    banned: boolean;
    plan: string;
    plan_expires_at: string;
    created: string;
    internal_notes: string;
    [key: string]: unknown;
}

interface AdminLink {
    id: string;
    user_id: string;
    destination_url: string;
    slug: string;
    active: boolean;
    created: string;
    [key: string]: unknown;
}

interface AdminClick {
    id: string;
    os: string;
    country: string;
    created: string;
    link_id?: { user_id: string };
    [key: string]: unknown;
}

export default function AdminUserProfile() {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();

    const [user, setUser] = useState<AdminUser | null>(null);
    const [links, setLinks] = useState<AdminLink[]>([]);
    const [clicks, setClicks] = useState<AdminClick[]>([]);
    const [loading, setLoading] = useState(true);
    const [internalNotes, setInternalNotes] = useState("");
    const [savingNotes, setSavingNotes] = useState(false);
    const [chartData, setChartData] = useState<Record<string, unknown>[]>([]);
    const [customDays, setCustomDays] = useState("30");
    const [selectedPlan, setSelectedPlan] = useState("creator");
    const [updatingPlan, setUpdatingPlan] = useState(false);

    useEffect(() => {
        if (!id) return;
        fetchUserData();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [id]);

    const fetchUserData = async () => {
        setLoading(true);
        try {
            // Fetch User
            const userData = await pb.collection("users").getOne<AdminUser>(id as string, { requestKey: null });
            setUser(userData);
            setInternalNotes(userData.internal_notes || "");
            setSelectedPlan(userData.plan || "creator");

            // Fetch Links
            const linksData = await pb.collection("links").getList(1, 50, {
                filter: `user_id="${id}"`,
                sort: "-created",
                requestKey: null
            });
            setLinks(linksData.items as unknown as AdminLink[]);

            // Fetch Clicks
            const clicksData = await pb.collection("clicks").getList(1, 100, {
                filter: `link_id.user_id="${id}"`,
                sort: "-created",
                expand: "link_id",
                requestKey: null
            });
            setClicks(clicksData.items as unknown as AdminClick[]);

            // Generate Chart Data (Last 7 days)
            const data = [];
            const now = new Date();
            for (let i = 6; i >= 0; i--) {
                const d = new Date(now.getTime() - i * 24 * 60 * 60 * 1000);
                data.push({
                    time: d.toLocaleDateString('en-US', { weekday: 'short' }),
                    clicks: clicksData.items.filter(c => new Date(c.created).getDate() === d.getDate() && new Date(c.created).getMonth() === d.getMonth()).length
                });
            }
            setChartData(data);

        } catch (err) {
            console.error("Failed to load user data:", err);
            toast.error("User not found or error loading data");
            navigate("/admin/users");
        } finally {
            setLoading(false);
        }
    };

    const handleNotesSave = async () => {
        setSavingNotes(true);
        try {
            await pb.collection("users").update(id as string, { internal_notes: internalNotes });
            toast.success("Internal notes saved");
            setUser({ ...user, internal_notes: internalNotes });
        } catch (err) {
            toast.error("Failed to save notes");
        } finally {
            setSavingNotes(false);
        }
    };

    const handleUpdatePlan = async () => {
        setUpdatingPlan(true);
        try {
            const updateData: Record<string, string | null> = { plan: selectedPlan };
            if (selectedPlan !== "creator") {
                const days = Math.max(1, parseInt(customDays) || 30);
                const expires = new Date();
                expires.setDate(expires.getDate() + days);
                updateData.plan_expires_at = expires.toISOString();
            } else {
                updateData.plan_expires_at = null;
            }

            await pb.collection("users").update(id as string, updateData);
            setUser({ ...user, plan: selectedPlan, plan_expires_at: updateData.plan_expires_at });
            toast.success(`Plan updated to ${selectedPlan}`);
        } catch (err: any) {
            console.error("Failed to update plan", err);
            console.error("Detailed error data:", err?.data);
            toast.error("Failed to update plan");
        } finally {
            setUpdatingPlan(false);
        }
    };

    const toggleLinkStatus = async (linkId: string, currentStatus: boolean) => {
        try {
            await pb.collection("links").update(linkId, { active: !currentStatus });
            setLinks(links.map(l => l.id === linkId ? { ...l, active: !currentStatus } : l));
            toast.success(currentStatus ? "Link deactivated" : "Link activated");
        } catch (err) {
            toast.error("Could not update link status");
        }
    };

    const toggleUserBan = async () => {
        try {
            const newStatus = !user.banned;
            await pb.collection("users").update(id as string, { banned: newStatus });
            setUser({ ...user, banned: newStatus });
            toast.success(newStatus ? "User has been banned" : "User ban lifted");
        } catch (err) {
            toast.error("Failed to change ban status");
        }
    };

    const requestPasswordReset = async () => {
        try {
            await pb.collection("users").requestPasswordReset(user.email);
            toast.success(`Password reset email sent to ${user.email}`);
        } catch (err) {
            toast.error("Failed to send reset email");
        }
    };

    if (loading) {
        return (
            <div className="h-full flex items-center justify-center pt-20">
                <div className="w-8 h-8 border-2 border-accent border-t-transparent rounded-full animate-spin" />
            </div>
        );
    }

    if (!user) return null;

    const totalClicks = clicks.length; // From our top 100 sample or we could aggregate differently
    const totalLinks = links.length;
    const lastClick = clicks.length > 0 ? clicks[0] : null;

    return (
        <div className="max-w-6xl mx-auto space-y-6 pt-6 pb-12">

            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
                <div className="flex items-start gap-4">
                    <button
                        onClick={() => navigate("/dashboard")}
                        className="p-2 -ml-2 rounded-lg text-muted-foreground hover:bg-surface-hover hover:text-foreground transition-colors"
                    >
                        <ChevronLeft className="w-5 h-5" />
                    </button>
                    <div>
                        <div className="flex items-center gap-3">
                            <h1 className="text-2xl font-bold text-foreground">{user.name || "Unnamed User"}</h1>
                            {user.banned && (
                                <span className="px-2 py-0.5 rounded text-xs font-bold bg-red-500/20 text-red-500 uppercase tracking-wider">
                                    Banned
                                </span>
                            )}
                            <span className="px-2 py-0.5 rounded text-xs font-bold bg-accent/20 text-accent uppercase tracking-wider">
                                {user.plan || "Creator"}
                            </span>
                        </div>
                        <p className="text-sm text-muted-foreground mt-1 flex items-center gap-2">
                            {user.email} <span className="text-border text-xs">тАв</span> ID: {user.id} <span className="text-border text-xs">тАв</span> Joined: {new Date(user.created).toLocaleDateString()}
                        </p>
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <button
                        onClick={requestPasswordReset}
                        className="px-4 py-2 bg-surface border border-border text-foreground text-sm font-medium rounded-xl hover:bg-surface-hover transition-colors"
                    >
                        Send Password Reset
                    </button>
                    {!user.banned ? (
                        <AlertDialog>
                            <AlertDialogTrigger asChild>
                                <button className="px-4 py-2 bg-red-500/10 text-red-500 text-sm font-medium rounded-xl hover:bg-red-500/20 transition-colors">
                                    Ban User
                                </button>
                            </AlertDialogTrigger>
                            <AlertDialogContent className="bg-surface border-border">
                                <AlertDialogHeader>
                                    <AlertDialogTitle className="text-foreground">Ban User Account</AlertDialogTitle>
                                    <AlertDialogDescription className="text-muted-foreground">
                                        This will immediately suspend the user's access to the dashboard. Their short links may also stop working depending on platform rules.
                                    </AlertDialogDescription>
                                </AlertDialogHeader>
                                <AlertDialogFooter>
                                    <AlertDialogCancel className="bg-background border-border text-foreground hover:bg-surface-hover">Cancel</AlertDialogCancel>
                                    <AlertDialogAction className="bg-red-500 hover:bg-red-600 text-white" onClick={toggleUserBan}>
                                        Yes, Ban User
                                    </AlertDialogAction>
                                </AlertDialogFooter>
                            </AlertDialogContent>
                        </AlertDialog>
                    ) : (
                        <button
                            onClick={toggleUserBan}
                            className="px-4 py-2 bg-emerald-500/10 text-emerald-500 text-sm font-medium rounded-xl hover:bg-emerald-500/20 transition-colors"
                        >
                            Unban User
                        </button>
                    )}
                </div>
            </div>

            {/* Tabs */}
            <Tabs defaultValue="overview" className="w-full">
                <TabsList className="bg-surface border border-border w-full justify-start rounded-xl p-1 h-auto mb-6">
                    <TabsTrigger value="overview" className="data-[state=active]:bg-background data-[state=active]:text-foreground text-muted-foreground py-2 px-4 rounded-lg flex items-center gap-2">
                        <BarChart3 className="w-4 h-4" /> Overview
                    </TabsTrigger>
                    <TabsTrigger value="links" className="data-[state=active]:bg-background data-[state=active]:text-foreground text-muted-foreground py-2 px-4 rounded-lg flex items-center gap-2">
                        <LinkIcon className="w-4 h-4" /> Links ({totalLinks})
                    </TabsTrigger>
                    <TabsTrigger value="billing" className="data-[state=active]:bg-background data-[state=active]:text-foreground text-muted-foreground py-2 px-4 rounded-lg flex items-center gap-2">
                        <CreditCard className="w-4 h-4" /> Billing & Notes
                    </TabsTrigger>
                    <TabsTrigger value="security" className="data-[state=active]:bg-background data-[state=active]:text-foreground text-muted-foreground py-2 px-4 rounded-lg flex items-center gap-2">
                        <ShieldAlert className="w-4 h-4" /> Security
                    </TabsTrigger>
                </TabsList>

                {/* OVERVIEW TAB */}
                <TabsContent value="overview" className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        <div className="bg-surface border border-border rounded-2xl p-6">
                            <h3 className="text-sm font-medium text-muted-foreground">Total Links</h3>
                            <p className="text-3xl font-bold text-foreground mt-2">{totalLinks}</p>
                        </div>
                        <div className="bg-surface border border-border rounded-2xl p-6">
                            <h3 className="text-sm font-medium text-muted-foreground">Recent Clicks (Sample)</h3>
                            <p className="text-3xl font-bold text-foreground mt-2">{totalClicks}</p>
                        </div>
                        <div className="bg-surface border border-border rounded-2xl p-6">
                            <h3 className="text-sm font-medium text-muted-foreground">Last Known Device</h3>
                            <p className="text-lg font-medium text-foreground mt-2 truncate">
                                {lastClick ? (
                                    <span className="flex items-center gap-2"><Smartphone className="w-4 h-4" /> {lastClick.os} / {lastClick.country}</span>
                                ) : "No data"}
                            </p>
                        </div>
                    </div>

                    <div className="bg-surface border border-border rounded-2xl p-6">
                        <h2 className="text-lg font-bold text-foreground mb-6">Click Activity (7 Days)</h2>
                        <div className="h-72">
                            <ResponsiveContainer width="100%" height="100%">
                                <AreaChart data={chartData}>
                                    <defs>
                                        <linearGradient id="colorAdminClicks" x1="0" y1="0" x2="0" y2="1">
                                            <stop offset="5%" stopColor="#10b981" stopOpacity={0.3} />
                                            <stop offset="95%" stopColor="#10b981" stopOpacity={0} />
                                        </linearGradient>
                                    </defs>
                                    <CartesianGrid strokeDasharray="3 3" stroke="#2a2a2a" vertical={false} />
                                    <XAxis dataKey="time" stroke="#666" fontSize={12} tickLine={false} axisLine={false} />
                                    <YAxis stroke="#666" fontSize={12} tickLine={false} axisLine={false} allowDecimals={false} />
                                    <RechartsTooltip contentStyle={{ backgroundColor: '#111', borderColor: '#333', borderRadius: '8px' }} itemStyle={{ color: '#10b981' }} />
                                    <Area type="monotone" dataKey="clicks" stroke="#10b981" strokeWidth={2} fillOpacity={1} fill="url(#colorAdminClicks)" />
                                </AreaChart>
                            </ResponsiveContainer>
                        </div>
                    </div>
                </TabsContent>

                {/* LINKS TAB */}
                <TabsContent value="links">
                    <div className="bg-surface border border-border rounded-2xl overflow-hidden">
                        <div className="overflow-x-auto">
                            <table className="w-full">
                                <thead>
                                    <tr className="border-b border-border bg-sidebar-accent/30 text-left text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                                        <th className="px-6 py-4">Link Details</th>
                                        <th className="px-6 py-4">Status</th>
                                        <th className="px-6 py-4">Created</th>
                                        <th className="px-6 py-4 text-right">Actions</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-border">
                                    {links.length === 0 ? (
                                        <tr>
                                            <td colSpan={4} className="px-6 py-12 text-center text-muted-foreground">
                                                User has not created any links.
                                            </td>
                                        </tr>
                                    ) : (
                                        links.map((link) => {
                                            const shortUrl = `${window.location.host}/${link.slug}`;
                                            return (
                                                <tr key={link.id} className="hover:bg-surface-hover transition-colors">
                                                    <td className="px-6 py-4">
                                                        <div className="flex flex-col max-w-[250px] sm:max-w-xs md:max-w-sm">
                                                            <a href={`http://${shortUrl}`} target="_blank" rel="noopener noreferrer" className="font-medium text-accent hover:underline flex items-center gap-1.5 truncate">
                                                                {shortUrl}
                                                                <ExternalLink className="w-3 h-3 shrink-0" />
                                                            </a>
                                                            <span className="text-xs text-muted-foreground truncate mt-1" title={link.destination_url}>
                                                                {link.destination_url}
                                                            </span>
                                                        </div>
                                                    </td>
                                                    <td className="px-6 py-4">
                                                        <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium ${!link.active ? 'bg-red-500/10 text-red-500' : 'bg-emerald-500/10 text-emerald-500'}`}>
                                                            {!link.active ? <Ban className="w-3 h-3" /> : <Check className="w-3 h-3" />}
                                                            {!link.active ? 'Disabled' : 'Active'}
                                                        </span>
                                                    </td>
                                                    <td className="px-6 py-4 text-sm text-muted-foreground">
                                                        {new Date(link.created).toLocaleDateString()}
                                                    </td>
                                                    <td className="px-6 py-4 text-right">
                                                        <AlertDialog>
                                                            <AlertDialogTrigger asChild>
                                                                <button className={`p-2 rounded-lg transition-colors text-sm font-medium border ${link.active ? 'bg-background border-border text-foreground hover:bg-red-500/10 hover:text-red-500 hover:border-red-500/50' : 'bg-background border-border text-foreground hover:bg-emerald-500/10 hover:text-emerald-500 hover:border-emerald-500/50'}`}>
                                                                    {link.active ? 'Block Link' : 'Unblock'}
                                                                </button>
                                                            </AlertDialogTrigger>
                                                            <AlertDialogContent className="bg-surface border-border">
                                                                <AlertDialogHeader>
                                                                    <AlertDialogTitle className="text-foreground">
                                                                        {link.active ? 'Block malicious link?' : 'Restore link functionality?'}
                                                                    </AlertDialogTitle>
                                                                    <AlertDialogDescription className="text-muted-foreground">
                                                                        {link.active ? "If this link violates terms of service, blocking it will immediately show a 404 to visitors." : "Restoring this link will allow visitors to be redirected."}
                                                                    </AlertDialogDescription>
                                                                </AlertDialogHeader>
                                                                <AlertDialogFooter>
                                                                    <AlertDialogCancel className="bg-background border-border text-foreground hover:bg-surface-hover">Cancel</AlertDialogCancel>
                                                                    <AlertDialogAction className={link.active ? "bg-red-500 hover:bg-red-600 text-white" : "bg-emerald-500 hover:bg-emerald-600 text-white"} onClick={() => toggleLinkStatus(link.id, link.active)}>
                                                                        Confirm
                                                                    </AlertDialogAction>
                                                                </AlertDialogFooter>
                                                            </AlertDialogContent>
                                                        </AlertDialog>
                                                    </td>
                                                </tr>
                                            );
                                        })
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </TabsContent>

                {/* BILLING & NOTES TAB */}
                <TabsContent value="billing" className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

                        <div className="bg-surface border border-border rounded-2xl p-6">
                            <div className="flex items-center gap-3 mb-6">
                                <div className="p-2 bg-accent/20 text-accent rounded-lg">
                                    <CreditCard className="w-5 h-5" />
                                </div>
                                <h2 className="text-lg font-bold text-foreground">Subscription Management</h2>
                            </div>

                            <div className="space-y-4">
                                <div className="space-y-2">
                                    <label className="text-sm font-medium text-foreground">Assign Plan</label>
                                    <div className="flex gap-3">
                                        <div className="flex-1">
                                            <Select value={selectedPlan} onValueChange={setSelectedPlan}>
                                                <SelectTrigger className="w-full bg-background border-border">
                                                    <SelectValue placeholder="Select plan" />
                                                </SelectTrigger>
                                                <SelectContent className="bg-surface border-border">
                                                    <SelectItem value="creator">Free (Creator)</SelectItem>
                                                    <SelectItem value="pro">Creator Pro</SelectItem>
                                                    <SelectItem value="agency">Agency</SelectItem>
                                                </SelectContent>
                                            </Select>
                                        </div>
                                        {selectedPlan !== 'creator' && (
                                            <div className="w-24 relative">
                                                <input
                                                    type="number"
                                                    value={customDays}
                                                    onChange={(e) => setCustomDays(e.target.value)}
                                                    min="1"
                                                    className="w-full px-3 py-2 rounded-md bg-background border border-border text-sm focus:outline-none focus:border-accent/50 text-foreground"
                                                    placeholder="Days"
                                                />
                                            </div>
                                        )}
                                        <button
                                            onClick={handleUpdatePlan}
                                            disabled={updatingPlan}
                                            className="px-4 py-2 bg-accent text-white text-sm font-medium rounded-md hover:bg-accent/90 transition-colors disabled:opacity-50"
                                        >
                                            {updatingPlan ? "Wait..." : "Update"}
                                        </button>
                                    </div>
                                </div>

                                {user.plan && user.plan !== 'creator' && (
                                    <div className="p-4 bg-background border border-border rounded-xl flex items-center justify-between">
                                        <div>
                                            <p className="text-sm text-muted-foreground">Plan Expires At</p>
                                            <p className="text-sm font-medium text-foreground">
                                                {user.plan_expires_at ? new Date(user.plan_expires_at).toLocaleDateString() : 'Never'}
                                            </p>
                                        </div>
                                    </div>
                                )}
                            </div>
                        </div>

                        <div className="bg-surface border border-border rounded-2xl p-6 flex flex-col">
                            <div className="flex items-center gap-3 mb-6">
                                <div className="p-2 bg-blue-500/20 text-blue-500 rounded-lg">
                                    <User className="w-5 h-5" />
                                </div>
                                <h2 className="text-lg font-bold text-foreground">Internal Staff Notes</h2>
                            </div>

                            <p className="text-sm text-muted-foreground mb-4">
                                These notes are only visible to administrators. Use them to track support tickets, refunds, or manual plan assignments.
                            </p>

                            <textarea
                                value={internalNotes}
                                onChange={(e) => setInternalNotes(e.target.value)}
                                placeholder="E.g., Granted Pro plan on 15.02.2025 due to a billing issue..."
                                className="flex-1 w-full min-h-[150px] p-4 bg-background border border-border rounded-xl text-sm focus:outline-none focus:border-accent/50 transition-colors resize-none text-foreground placeholder-muted-foreground"
                            />

                            <div className="mt-4 flex justify-end">
                                <button
                                    onClick={handleNotesSave}
                                    disabled={savingNotes || internalNotes === user.internal_notes}
                                    className="px-4 py-2 bg-accent text-white text-sm font-medium rounded-xl hover:bg-accent/90 transition-colors disabled:opacity-50"
                                >
                                    {savingNotes ? "Saving..." : "Save Notes"}
                                </button>
                            </div>
                        </div>

                    </div>
                </TabsContent>

                {/* SECURITY TAB */}
                <TabsContent value="security" className="space-y-6">
                    <div className="bg-surface border border-border rounded-2xl p-6">
                        <div className="flex items-center gap-3 mb-6">
                            <div className="p-2 bg-red-500/20 text-red-500 rounded-lg">
                                <ShieldAlert className="w-5 h-5" />
                            </div>
                            <h2 className="text-lg font-bold text-foreground">Security Audit & Access</h2>
                        </div>

                        <div className="space-y-6">
                            <div className="p-4 bg-red-500/5 border border-red-500/20 rounded-xl flex items-center justify-between">
                                <div>
                                    <h3 className="font-medium text-foreground">Account Status: {user.banned ? "Banned" : "Active"}</h3>
                                    <p className="text-sm text-muted-foreground mt-1">If banned, the user will be logged out and unable to access the dashboard.</p>
                                </div>
                                <button
                                    onClick={toggleUserBan}
                                    className={`px-4 py-2 text-sm font-medium rounded-xl transition-colors ${user.banned ? 'bg-emerald-500/10 text-emerald-500 hover:bg-emerald-500/20' : 'bg-red-500/10 text-red-500 hover:bg-red-500/20'}`}
                                >
                                    {user.banned ? "Remove Ban" : "Ban Account"}
                                </button>
                            </div>

                            <div>
                                <h3 className="text-sm font-semibold text-foreground uppercase tracking-wider mb-4">Recent Connection IPs (via Link Clicks)</h3>
                                <div className="space-y-2">
                                    {clicks.slice(0, 5).map((click) => (
                                        <div key={click.id} className="flex items-center justify-between p-3 bg-background border border-border rounded-lg">
                                            <div className="flex items-center gap-3">
                                                <MapPin className="w-4 h-4 text-muted-foreground" />
                                                <span className="text-sm text-foreground">{click.country || "Unknown Country"}</span>
                                                <span className="text-xs text-muted-foreground hidden sm:inline">- {click.os}</span>
                                            </div>
                                            <span className="text-xs font-mono text-muted-foreground">{new Date(click.created).toLocaleString()}</span>
                                        </div>
                                    ))}
                                    {clicks.length === 0 && (
                                        <p className="text-sm text-muted-foreground p-4 bg-background border border-border rounded-lg">No recent link activity to infer IPs from.</p>
                                    )}
                                </div>
                            </div>
                        </div>

                    </div>
                </TabsContent>

            </Tabs>
        </div >
    );
}

import { useState, useEffect } from "react";
import { pb } from "@/lib/pocketbase";
import { Search, ChevronLeft, ChevronRight, UserX, ShieldAlert, Check } from "lucide-react";
import { toast } from "sonner";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { useNavigate } from "react-router-dom";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { PLANS, PlanType } from "@/lib/plans";
import { BarChart3, Link as LinkIcon, Edit2, MapPin, ExternalLink } from "lucide-react";

type UserRecord = {
    id: string;
    email: string;
    name: string;
    plan: PlanType;
    role: string;
    created: string;
    banned?: boolean;
    stats?: { links: number, clicks: number };
    metrics?: { device: string, country: string };
};

export default function AdminUsers() {
    const [users, setUsers] = useState<UserRecord[]>([]);
    const [loading, setLoading] = useState(true);
    const [page, setPage] = useState(1);
    const [totalPages, setTotalPages] = useState(1);
    const [search, setSearch] = useState("");
    const navigate = useNavigate();

    const fetchUsers = async () => {
        setLoading(true);
        try {
            const result = await pb.collection("users").getList(page, 20, {
                sort: "-created",
                filter: search ? `email ~ "${search}" || id ~ "${search}"` : "",
                requestKey: null
            });
            setUsers(result.items as unknown as UserRecord[]);
            setTotalPages(result.totalPages);
        } catch (err) {
            console.error("Failed to fetch users", err);
            toast.error("Failed to load users");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchUsers();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [page, search]);

    const handlePlanChange = async (userId: string, newPlan: string) => {
        try {
            const updateData: Record<string, string | null> = { plan: newPlan };
            if (newPlan !== "creator") {
                const expires = new Date();
                expires.setDate(expires.getDate() + 30);
                updateData.plan_expires_at = expires.toISOString();
            } else {
                updateData.plan_expires_at = null;
            }

            await pb.collection("users").update(userId, updateData);

            if (newPlan !== "creator") {
                try {
                    await pb.collection("billing").create({
                        user_id: userId,
                        plan: newPlan,
                        amount: newPlan === "pro" ? 15 : 29,
                        status: "active",
                        payment_method: "Given"
                    });
                } catch (billingErr) {
                    console.warn("Billing record creation failed (non-critical):", billingErr);
                }
            }

            toast.success("User plan updated successfully");
            setUsers(users.map(u => u.id === userId ? { ...u, plan: newPlan as PlanType } : u));
        } catch (err: any) {
            console.error("Failed to update plan", err);
            console.error("Detailed PB error:", err?.data);
            toast.error("Could not update user plan");
        }
    };

    const handleEditUser = (user: UserRecord) => {
        navigate(`/admin/users/${user.id}`);
    };

    const handleAction = async (userId: string, action: 'ban' | 'delete') => {
        try {
            if (action === 'delete') {
                await pb.collection("users").delete(userId);
                toast.success("User deleted successfully");
                setUsers(users.filter(u => u.id !== userId));
            } else if (action === 'ban') {
                // Requires adding a `banned` boolean field to users collection later if needed.
                // For now, we'll try to update it, and if the schema lacks it, it's ignored or errors.
                await pb.collection("users").update(userId, { banned: true });
                toast.success("User banned");
                fetchUsers();
            }
        } catch (err) {
            console.error(`Failed to ${action} user`, err);
            toast.error(`Could not ${action} user`);
        }
    };

    return (
        <div className="space-y-6 pt-6 max-w-6xl mx-auto">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div className="flex items-center gap-4">
                    <button
                        onClick={() => navigate('/dashboard')}
                        className="p-2 -ml-2 rounded-lg text-muted-foreground hover:bg-surface-hover hover:text-foreground transition-colors"
                    >
                        <ChevronLeft className="w-5 h-5" />
                    </button>
                    <div>
                        <h1 className="text-2xl font-bold text-foreground">User Management</h1>
                        <p className="text-sm text-muted-foreground mt-1">Manage all accounts on the platform</p>
                    </div>
                </div>

                <div className="relative w-full sm:w-72">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                    <input
                        type="text"
                        placeholder="Search email or ID..."
                        value={search}
                        onChange={(e) => { setSearch(e.target.value); setPage(1); }}
                        className="w-full pl-9 pr-4 py-2 bg-surface border border-border rounded-xl text-sm focus:outline-none focus:border-accent/50 transition-all placeholder:text-muted-foreground"
                    />
                </div>
            </div>

            <div className="bg-surface border border-border rounded-2xl overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full">
                        <thead>
                            <tr className="border-b border-border bg-sidebar-accent/30 text-left text-xs font-semibold text-muted-foreground uppercase tracking-wider">
                                <th className="px-6 py-4">User</th>
                                <th className="px-6 py-4">Role / Plan</th>
                                <th className="px-6 py-4">Status</th>
                                <th className="px-6 py-4 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-border">
                            {loading ? (
                                <tr>
                                    <td colSpan={4} className="px-6 py-12 text-center text-muted-foreground">
                                        <div className="w-6 h-6 border-2 border-accent border-t-transparent rounded-full animate-spin mx-auto" />
                                    </td>
                                </tr>
                            ) : users.length === 0 ? (
                                <tr>
                                    <td colSpan={4} className="px-6 py-12 text-center text-muted-foreground">
                                        No users found matching your search.
                                    </td>
                                </tr>
                            ) : (
                                users.map((user) => (
                                    <tr key={user.id} className="hover:bg-surface-hover transition-colors">
                                        <td className="px-6 py-4">
                                            <div className="flex flex-col">
                                                <span className="font-medium text-foreground">{user.email}</span>
                                                <span className="text-xs text-muted-foreground font-mono mt-0.5">ID: {user.id}</span>
                                                <span className="text-xs text-muted-foreground mt-0.5">
                                                    Joined {new Date(user.created).toLocaleDateString()}
                                                </span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="space-y-2">
                                                <div className="flex items-center gap-2">
                                                    {user.role === 'admin' && (
                                                        <span className="text-[10px] uppercase font-bold px-2 py-0.5 rounded bg-red-500/20 text-red-500">Admin</span>
                                                    )}
                                                    <span className="text-xs font-medium px-2 py-0.5 rounded bg-surface border border-border uppercase">
                                                        {user.plan || "creator"}
                                                    </span>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium ${user.banned ? 'bg-red-500/10 text-red-500' : 'bg-accent/10 text-accent'
                                                }`}>
                                                {user.banned ? <ShieldAlert className="w-3 h-3" /> : <Check className="w-3 h-3" />}
                                                {user.banned ? 'Banned' : 'Active'}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <div className="flex items-center justify-end gap-2">
                                                <button
                                                    onClick={() => handleEditUser(user)}
                                                    className="p-2 text-muted-foreground hover:bg-accent/10 hover:text-accent rounded-lg transition-colors"
                                                    title="Edit User"
                                                >
                                                    <Edit2 className="w-4 h-4" />
                                                </button>
                                                <AlertDialog>
                                                    <AlertDialogTrigger asChild>
                                                        <button className="p-2 text-muted-foreground hover:bg-red-500/10 hover:text-red-500 rounded-lg transition-colors">
                                                            <UserX className="w-4 h-4" />
                                                        </button>
                                                    </AlertDialogTrigger>
                                                    <AlertDialogContent className="bg-surface border-border">
                                                        <AlertDialogHeader>
                                                            <AlertDialogTitle className="text-foreground">Delete User Account</AlertDialogTitle>
                                                            <AlertDialogDescription className="text-muted-foreground">
                                                                Are you sure? This action cannot be undone. This will permanently delete
                                                                the user <strong>{user.email}</strong> and all associated links and data.
                                                            </AlertDialogDescription>
                                                        </AlertDialogHeader>
                                                        <AlertDialogFooter>
                                                            <AlertDialogCancel className="bg-background border-border text-foreground hover:bg-surface-hover">Cancel</AlertDialogCancel>
                                                            <AlertDialogAction
                                                                className="bg-red-500 hover:bg-red-600 text-white"
                                                                onClick={() => handleAction(user.id, 'delete')}
                                                            >
                                                                Delete Permanently
                                                            </AlertDialogAction>
                                                        </AlertDialogFooter>
                                                    </AlertDialogContent>
                                                </AlertDialog>
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>

                {/* Pagination */}
                {totalPages > 1 && (
                    <div className="px-6 py-4 border-t border-border flex items-center justify-between">
                        <span className="text-sm text-muted-foreground">
                            Page {page} of {totalPages}
                        </span>
                        <div className="flex gap-2">
                            <button
                                disabled={page === 1}
                                onClick={() => setPage(p => Math.max(1, p - 1))}
                                className="p-2 border border-border rounded-lg disabled:opacity-50 text-foreground hover:bg-surface-hover transition-colors"
                            >
                                <ChevronLeft className="w-4 h-4" />
                            </button>
                            <button
                                disabled={page === totalPages}
                                onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                                className="p-2 border border-border rounded-lg disabled:opacity-50 text-foreground hover:bg-surface-hover transition-colors"
                            >
                                <ChevronRight className="w-4 h-4" />
                            </button>
                        </div>
                    </div>
                )}
            </div>

        </div>
    );
}
